import React,{useState,useEffect} from "react";
import {Bar} from "react-chartjs-2";
import {
Chart as ChartJS,
CategoryScale,
LinearScale,
BarElement,
Title,
Tooltip,
Legend
} from "chart.js";

ChartJS.register(
CategoryScale,
LinearScale,
BarElement,
Title,
Tooltip,
Legend
);

function App(){

const [transactions,setTransactions] = useState([]);
const [amount,setAmount] = useState("");

useEffect(()=>{
fetchTransactions();
},[]);

const fetchTransactions = async () =>{

const res = await fetch("http://localhost:5000/transactions");
const data = await res.json();

setTransactions(data);

}

const addTransaction = async () =>{

const res = await fetch("http://localhost:5000/transaction",{

method:"POST",
headers:{
"Content-Type":"application/json"
},
body:JSON.stringify({amount})

});

await res.json();

fetchTransactions();

}

const chartData = {
labels: transactions.map((t,i)=>"T"+(i+1)),
datasets:[
{
label:"Savings",
data: transactions.map(t=>t.saved)
}
]
};

const totalSavings =
transactions.reduce((sum,t)=>sum + t.saved,0);

return(

<div style={{textAlign:"center",marginTop:"50px"}}>

<h1>Round-Up Savings Dashboard</h1>

<input
type="number"
placeholder="Enter transaction"
value={amount}
onChange={(e)=>setAmount(e.target.value)}
/>

<br/><br/>

<button onClick={addTransaction}>
Add Transaction
</button>

<h2>Total Saved ₹{totalSavings.toFixed(2)}</h2>

<div style={{width:"600px",margin:"auto"}}>
<Bar data={chartData}/>
</div>

<h2>Transaction History</h2>

<ul>
{transactions.map((t,i)=>(
<li key={i}>
Spent ₹{t.amount} → Saved ₹{t.saved}
</li>
))}
</ul>

</div>

);

}

export default App;
